import java.util.*;class NQueens{static int n;static int[] col;static boolean isSafe(int r,int c){for(int i=0;i<r;i++)if(col[i]==c||Math.abs(col[i]-c)==Math.abs(i-r))return false;return true;}static void solve(int r){if(r==n){for(int i=0;i<n;i++)System.out.print(col[i]+" ");System.out.println();return;}for(int c=0;c<n;c++){if(isSafe(r,c)){col[r]=c;solve(r+1);}}}public static void main(String[] a){Scanner s=new Scanner(System.in);n=s.nextInt();col=new int[n];solve(0);}}